const dateString = $json.date || "";
const date = new Date(dateString + "T12:00:00");
const dayOfWeek = date.getDay(); // 0=Dom, 1=Lun, 2=Mar, 3=Mié, 4=Jue, 5=Vie, 6=Sáb

// 1. SEGURIDAD: CONTROL DE FECHA INVÁLIDA
if (isNaN(dayOfWeek)) {
  return [{
    json: {
      status: "closed",
      message: "Ha habido un problema entendiendo la fecha de tu cita. ¿Podrías indicarme el día de nuevo?"
    }
  }];
}

// 2. FINES DE SEMANA (CERRADO PARA TODOS)
if (dayOfWeek === 0 || dayOfWeek === 6) {
  return [{
    json: {
      status: "closed",
      message: "La clínica está cerrada los fines de semana. Atendemos de lunes a viernes. ¿Qué día te viene bien?"
    }
  }];
}

// 3. NORMALIZAR SERVICIO Y TIEMPOS
const servicio = ($json.servicio || "").toString().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").trim();

const esPlexr = servicio.includes("plexr") || servicio.includes("plexer") || servicio.includes("periorbital") || servicio.includes("perioral") || servicio.includes("fibromas") || servicio.includes("xantelasmas");
const duracionMin = esPlexr ? 60 : 30;

const fromTimeStr = $json.fromTime || "00:00";
const [fh, fm] = fromTimeStr.split(":").map(Number);
const fromTotal = (fh || 0) * 60 + (fm || 0);
const toTotal = fromTotal + duracionMin;

const toHH = String(Math.floor(toTotal / 60)).padStart(2, "0");
const toMM = String(toTotal % 60).padStart(2, "0");
const toTime = `${toHH}:${toMM}:00`;

// RUTA A: PLEXR
if (esPlexr) {
  if (dayOfWeek !== 2 && dayOfWeek !== 4) {
    return [{
      json: {
        status: "closed",
        message: "El Plexr solo puede realizarse los martes o jueves de 17:00 a 20:00, ya que requiere la presencia de la Dra. Rosa. ¿Te viene bien alguno de esos días?"
      }
    }];
  }
  if (fromTotal < 1020 || toTotal > 1200) {
    return [{
      json: {
        status: "closed",
        message: "El Plexr está disponible de 17:00 a 20:00 los martes y jueves con la Dra. Rosa. La sesión de 60 min debe finalizar antes de las 20:00."
      }
    }];
  }
  return [{ json: { status: "open", categoria: "plexr", date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];
}

// RUTA B1: DRA. ROSA SOLO (no requiere asistencias continuas, NO bloquea a Noa/Rosi)
const keywordsDraRosaSolo = [
  "esclerosis", "varice", "microespuma", "valoracion", "endolifting", "lipolaser", "manos"
];
const esDraRosaSolo = keywordsDraRosaSolo.some(k => servicio.includes(k));

// RUTA B2: DRA. ROSA ASISTIDA (bloquea a los 3)
const keywordsDraRosaAsistida = [
  "botox", "neuromodulador", "bruxismo", "hilos", "mesoterapia", "relleno", "labio", 
  "nariz", "ojera", "pomulo", "acido hialuronico", "skin booster", "inductor", 
  "colageno", "bioestimulacion", "carboxiterapia", "agresivo"
];
const esDraRosaAsistida = keywordsDraRosaAsistida.some(k => servicio.includes(k));

if (esDraRosaSolo || esDraRosaAsistida) {
  if (dayOfWeek !== 2 && dayOfWeek !== 4) {
    return [{
      json: {
        status: "closed",
        message: "Los tratamientos médicos de la Dra. Rosa solo están disponibles los martes y jueves de 17:00 a 20:00."
      }
    }];
  }
  if (fromTotal < 1020 || toTotal > 1200) {
    return [{
      json: {
        status: "closed",
        message: "La Dra. Rosa atiende de 17:00 a 20:00 los martes y jueves."
      }
    }];
  }
  const categoriaAsignada = esDraRosaAsistida ? "dra_rosa_asistida" : "dra_rosa_solo";
  return [{ json: { status: "open", categoria: categoriaAsignada, date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];
}

// RUTA C: HORARIO GENERAL (Maderoterapia y Resto para Noa / Rosi)
if (dayOfWeek === 1 || dayOfWeek === 3 || dayOfWeek === 5) {
  if (fromTotal < 960 || toTotal > 1200) { 
    return [{ json: { status: "closed", message: "Los lunes, miércoles y viernes atendemos de 16:00 a 20:00." } }];
  }
} else if (dayOfWeek === 2 || dayOfWeek === 4) {
  if (fromTotal < 720 || toTotal > 1200) { 
    return [{ json: { status: "closed", message: "Los martes y jueves atendemos de 12:00 a 20:00." } }];
  }
}

if (servicio.includes("maderoterapia facial")) {
  return [{ json: { status: "open", categoria: "rosi_only", date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];
}

return [{ json: { status: "open", categoria: "rosi_noa", date: $json.date, fromTime: fromTimeStr, toTime: toTime } }];

const items = $input.all();
const categoria = $('Clasificar y Validar').item.json.categoria;

const profesionalesOcupados = items
  .filter(item => item.json.start)
  .map(item => {
    const desc = item.json.description || item.json.summary || "";
    const match = desc.match(/PROFESIONAL:\s*(.+)/i);
    return match ? match[1].trim() : "desconocido";
  });

const rosiOcupada = profesionalesOcupados.some(p => p.toLowerCase().includes("rosi"));
const noaOcupada = profesionalesOcupados.some(p => p.toLowerCase().includes("noa"));
const draRosaOcupada = profesionalesOcupados.some(p => p.toLowerCase().includes("dra. rosa") || p.toLowerCase().includes("dra rosa"));

if (categoria === "dra_rosa_solo") {
  if (draRosaOcupada) return [{ json: { status: "busy", message: "La Dra. Rosa ya tiene una cita en ese horario." } }];
  return [{ json: { status: "free", profesional_asignada: "Dra. Rosa", categoria: "dra_rosa_solo", message: "Horario disponible." } }];
}

if (categoria === "dra_rosa_asistida") {
  if (draRosaOcupada || noaOcupada || rosiOcupada) {
    return [{ json: { status: "busy", message: "No hay disponibilidad suficiente en cabina para la Dra. Rosa en ese horario." } }];
  }
  return [{ json: { status: "free", profesional_asignada: "Dra. Rosa", categoria: "dra_rosa_asistida", message: "Horario disponible." } }];
}

if (categoria === "rosi_only") {
  if (rosiOcupada) return [{ json: { status: "busy", message: "Rosi ya tiene una cita en ese horario." } }];
  return [{ json: { status: "free", profesional_asignada: "Rosi", categoria: "rosi_only", message: "Horario disponible." } }];
}

if (categoria === "rosi_noa") {
  if (!rosiOcupada) return [{ json: { status: "free", profesional_asignada: "Rosi", categoria: "rosi_noa", message: "Horario disponible." } }];
  if (!noaOcupada) return [{ json: { status: "free", profesional_asignada: "Noa", categoria: "rosi_noa", message: "Horario disponible." } }];
  return [{ json: { status: "busy", message: "Tanto Rosi como Noa tienen citas en ese horario." } }];
}

if (categoria === "plexr") {
  if (draRosaOcupada || (rosiOcupada && noaOcupada)) {
    return [{ json: { status: "busy", message: "No hay disponibilidad para Plexr en ese horario (se requiere Dra Rosa y una asistente)." } }];
  }
  const asistente = !rosiOcupada ? "Rosi" : "Noa";
  return [{ json: { status: "free", profesional_asignada: asistente, categoria: "plexr", message: "Horario disponible para Plexr." } }];
}

return [{ json: { status: "free", profesional_asignada: "Rosi", categoria: categoria || "rosi_noa", message: "Horario disponible." } }];

